        $max_rows = $max_rows ?? 1000;
        $max_rows = max(0, (int)$max_rows);

        if (empty($database)) {
            return ['error' => 'Database name is required.'];
        }
        if (empty($sql)) {
            return ['error' => 'SQL query is required.'];
        }

        // Build DSN
        $dsn_parts = [];
