            ];
        }

        $elapsed = round(microtime(true) - $start, 4);

        // Determine query type
        $sql_upper = trim(strtoupper($sql));
        $is_select = preg_match('/^(SELECT|SHOW|DESCRIBE|EXPLAIN)\b/i', $sql_upper);
        $is_insert = preg_match('/^INSERT\b/i', $sql_upper);

